"Trimmer": dict(desc="Fine-grained ffmpeg trimming of retrieved scenes.",
inputs=["retrieved", "video_path"], outputs=["clips"], caps=["trimming"]),
"VideoEditor": dict(desc="Concatenate clips into one edited video.",
